import React from 'react';
import { BrowserRouter as Router, Routes, Route, useLocation } from 'react-router-dom';
import { AnimatePresence, motion, useReducedMotion } from 'framer-motion';
import Navbar from './components/Navbar';
import Home from './pages/Home';
import MapView from './pages/MapView';
import Login from './pages/Login';
import Register from './pages/Register';
import ForgotPassword from './pages/ForgotPassword';
import Profile from './pages/Profile';
import Itinerary from './pages/Itinerary'; 
import Safari from './pages/Safari'; // 1. ADD THIS IMPORT
import FuturisticBackground from './components/FuturisticBackground';

const RouteTransition: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const reduceMotion = useReducedMotion();

  return (
    <motion.div
      initial={reduceMotion ? { opacity: 1, y: 0 } : { opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      exit={reduceMotion ? { opacity: 0.98, y: 0 } : { opacity: 0, y: -6 }}
      transition={
        reduceMotion
          ? { duration: 0.12, ease: 'linear' }
          : { enter: { duration: 0.34, ease: 'easeOut' }, exit: { duration: 0.18, ease: 'easeInOut' } }
      }
      className="relative"
    >
      {children}
    </motion.div>
  );
};

const AppRoutes: React.FC = () => {
  const location = useLocation();

  return (
    <AnimatePresence mode="wait" initial={false}>
      <Routes location={location} key={location.pathname}>
        <Route path="/" element={<RouteTransition><Home /></RouteTransition>} />
        <Route path="/login" element={<RouteTransition><Login /></RouteTransition>} />
        <Route path="/register" element={<RouteTransition><Register /></RouteTransition>} />
        <Route path="/forgot-password" element={<RouteTransition><ForgotPassword /></RouteTransition>} />
        <Route path="/map" element={<RouteTransition><MapView /></RouteTransition>} />
        <Route path="/itinerary" element={<RouteTransition><Itinerary /></RouteTransition>} />
        <Route path="/profile" element={<RouteTransition><Profile /></RouteTransition>} />
      </Routes>
    </AnimatePresence>
  );
};

const App: React.FC = () => {
  return (
    <Router>
      <div className="relative isolate min-h-screen selection:bg-uncc-green/30 text-white">
        <FuturisticBackground showNoise showVignette />
        <div className="relative z-10 min-h-screen">
          <Navbar />
          <main className="relative z-10">
            <AppRoutes />
          </main>
        </div>
      </div>
    </Router>
  );
};

export default App;
